void solve(int CASE)
{
	ll n, h; cin >> n >> h;
	var a = vector<ll>(n + 2);
	a[0] = a[n + 1] = LNF;
	fa(i, 1, n)cin >> a[i];

	// 单调栈算当前位置如果排水，左边和右边的排水量
	var pre = vector<ll>(n + 1);
	var st = stack<int>();
	st.push(0);
	fa(i, 1, n) {
		while (a[st.top()] <= a[i])st.pop();
		st.push(i);
		var cst = st;
		var tmp = vector<pll>();
		while (cst.size()) {
			int now = cst.top();
			cst.pop();
			tmp.pb({ a[now], now });
		}
		fa(j, 0, vs(tmp) - 1) {
			ll len = abs(tmp[j].py - tmp[j + 1].py);
			ll high = h - tmp[j].px;
			pre[i] += len * high;
		}
	}

	var suf = vector<ll>(n + 1);
	while (st.size())st.pop();
	st.push(n + 1);
	fb(i, n, 1) {
		while (a[st.top()] <= a[i])st.pop();
		st.push(i);
		var cst = st;
		var tmp = vector<pll>();
		while (cst.size()) {
			int now = cst.top();
			cst.pop();
			tmp.pb({ a[now], now });
		}
		fa(j, 0, vs(tmp) - 1) {
			ll len = abs(tmp[j].py - tmp[j + 1].py);
			ll high = h - tmp[j].px;
			suf[i] += len * high;
		}
	}

	// 如果这个点被为排水口，会排多少水
	var f = vector<ll>(n + 1);
	fa(i, 1, n)f[i] = pre[i] + suf[i] - (h - a[i]);

	// 两点间最高的
	var mx = Vec2<pll>(n + 1, n + 1);
	fa(i, 1, n)fa(j, i, n) {
		if (i == j)mx[i][j] = { j, a[j] };
		else {
			if (a[j] > mx[i][j - 1].py)mx[i][j] = { j, a[j] };
			else mx[i][j] = mx[i][j - 1];
		}
	}

	ll ans = 0;
	fa(i, 1, n)fa(j, i, n)ans = max(ans, f[i] + f[j] - f[mx[i][j].px]);
	cout << ans << endl;
	return;
}
